# Update CSV
CSV_FILE = BASE / "เฉลยข้อสอบเคมี-ปรนัย.csv"
expl_map = {e["id"]: e["explanation"] for e in EXPLANATIONS}

with open(CSV_FILE, encoding='utf-8-sig') as f:
    rows = list(csv.DictReader(f))
    fieldnames = list(rows[0].keys())

updated_csv = 0
for r in rows:
    year = int(r['ปี'].replace('ปี ','').replace('ปี','').strip()) - 2500
    qnum = int(r['ข้อที่'])
    qid = f'y{year}-q{qnum}'
    if qid in expl_map and r['คำอธิบาย'].startswith('(verified)'):
        r['คำอธิบาย'] = expl_map[qid]
        updated_csv += 1

import io
out = io.StringIO()
w = csv.DictWriter(out, fieldnames=fieldnames)
w.writeheader()
w.writerows(rows)
with open(CSV_FILE, 'w', encoding='utf-8-sig', newline='') as f:
    f.write(out.getvalue())
print(f"CSV: อัปเดต {updated_csv} แถว")

# Update TS
TS_FILE = BASE / "src/data/chemistry/pastExamQuestions.ts"
text = TS_FILE.read_text(encoding='utf-8')
start = text.find("= [") + 2
depth = 0; end = start
for i, ch in enumerate(text[start:], start):
    if ch == "[": depth += 1
    elif ch == "]":
        depth -= 1
        if depth == 0: end = i; break
arr = json.loads(text[start:end+1])

updated_ts = 0
for q in arr:
    qid = q.get('id','')
    if qid in expl_map:
        old = q.get('explanation','')
        if old.startswith('(verified)') or not old:
            q['explanation'] = expl_map[qid]
            updated_ts += 1

TS_FILE.write_text(
    text[:start] + json.dumps(arr, ensure_ascii=False, indent=2) + text[end+1:],
    encoding='utf-8'
)
print(f"TS: อัปเดต {updated_ts} ข้อ")
